import { useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [file, setFile] = useState(null);
    const [fileName, setFileName] = useState("");
    const [loading, setLoading] = useState(false);

    const analyzeResume = async () => {
        if (resumeText.trim() === "") {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please paste your resume content first."]
            });
            return;
        }

        setLoading(true);

        try {
            const response = await fetch("http://localhost:5000/analyze", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ resumeText, jobDescription })
            });

            const data = await response.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Error connecting to backend."]
            });
        }

        setLoading(false);
    };

    const uploadResume = async () => {
        if (!file) {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please choose a PDF file first."]
            });
            return;
        }

        setLoading(true);

        const formData = new FormData();
        formData.append("resume", file);

        try {
            const response = await fetch("http://localhost:5000/upload", {
                method: "POST",
                body: formData
            });

            const data = await response.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Error uploading PDF."]
            });
        }

        setLoading(false);
    };

    const tagStyle = {
        display: "inline-block",
        padding: "8px 12px",
        borderRadius: "20px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "bold"
    };

    const getScoreColor = (score) => {
        if (score >= 80) return "#28a745";
        if (score >= 60) return "#ffc107";
        return "#dc3545";
    };

    return (
        <div style={{
            minHeight: "100vh",
            backgroundColor: "#f4f7fb",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            fontFamily: "Arial",
            padding: "20px"
        }}>
            <div style={{
                backgroundColor: "white",
                padding: "30px",
                borderRadius: "12px",
                boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
                width: "800px"
            }}>
                <h1 style={{ textAlign: "center" }}>AI Resume Analyzer 🚀</h1>

                <p style={{ textAlign: "center" }}>
                    Upload PDF or paste resume + job description
                </p>

                <h3>Upload Resume PDF</h3>
                <input
                    type="file"
                    accept=".pdf"
                    onChange={(e) => {
                        setFile(e.target.files[0]);
                        setFileName(e.target.files[0]?.name || "");
                    }}
                />

                {fileName && (
                    <p style={{ fontSize: "14px", marginTop: "5px" }}>
                        Selected: {fileName}
                    </p>
                )}

                <div style={{ textAlign: "center", marginTop: "10px" }}>
                    <button onClick={uploadResume}>
                        {loading ? "Uploading..." : "Upload & Analyze PDF"}
                    </button>
                </div>

                <h3>Resume</h3>
                <textarea
                    placeholder="Paste resume..."
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                    style={{ width: "100%", height: "120px" }}
                />

                <h3>Job Description</h3>
                <textarea
                    placeholder="Paste job description..."
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                    style={{ width: "100%", height: "120px" }}
                />

                <div style={{ textAlign: "center", marginTop: "10px" }}>
                    <button onClick={analyzeResume}>
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "20px" }}>
                        <h3>Score: {analysis.score}/100</h3>

                        <div style={{
                            height: "15px",
                            background: "#ddd",
                            borderRadius: "10px"
                        }}>
                            <div style={{
                                width: `${analysis.score}%`,
                                background: getScoreColor(analysis.score),
                                height: "100%"
                            }} />
                        </div>

                        <h3>Matched Skills</h3>
                        <div style={{ display: "flex", flexWrap: "wrap" }}>
                            {analysis.matchedSkills.map((s, i) => (
                                <span key={i} style={{
                                    ...tagStyle,
                                    background: "#d4edda"
                                }}>
                  {s}
                </span>
                            ))}
                        </div>

                        <h3>Missing Skills</h3>
                        <div style={{ display: "flex", flexWrap: "wrap" }}>
                            {analysis.missingSkills.map((s, i) => (
                                <span key={i} style={{
                                    ...tagStyle,
                                    background: "#f8d7da"
                                }}>
                  {s}
                </span>
                            ))}
                        </div>

                        <h3>Suggestions</h3>
                        <ul>
                            {analysis.suggestions.map((s, i) => (
                                <li key={i}>{s}</li>
                            ))}
                        </ul>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
